The first derivative of \( x^2 \sin(x) \) is
\begin{align} \frac{d}{dx}x^2\sin(x) &= 2x\sin(x)+x^2\cos(x) \\ &= 2x\sin(x)+x^2\cos(x) \end{align}
The second derivative is
\begin{align} \frac{d^2}{dx^2}x^2\sin(x) &= 2\sin(x)+2x\cos(x)-2x\cos(x)-x^2\sin(x) \\ &= 2\sin(x)-x^2\sin(x) \end{align}
The third derivative is
\begin{align} \frac{d^3}{dx^3}x^2\sin(x) &= 2\cos(x)-2x\sin(x)+2x\sin(x)+x^2\cos(x) \\ &= 2\cos(x)+x^2\cos(x) \end{align}
The fourth derivative is
\begin{align} \frac{d^4}{dx^4}x^2\sin(x) &= 2\sin(x)+2x\cos(x)+2x\cos(x)-2x\sin(x)-x^2\cos(x) \\ &= 2\sin(x)-x^2\cos(x) \end{align}
The fifth derivative is
\begin{align} \frac{d^5}{dx^5}x^2\sin(x) &= 2\cos(x)-2x\sin(x)-2x\sin(x)+2x\sin(x)+x^2\cos(x) \\ &= 2\cos(x)+x^2\cos(x) \end{align}
The sixth derivative is
\begin{align} \frac{d^6}{dx^6}x^2\sin(x) &= 2\sin(x)+2x\cos(x)+2x\cos(x)-2x\sin(x)-x^2\cos(x) \\ &= 2\sin(x)-x^2\cos(x) \end{align}
The seventh derivative is
\begin{align} \frac{d^7}{dx^7}x^2\sin(x) &= 2\cos(x)-2x\sin(x)-2x\sin(x)+2x\sin(x)+x^2\cos(x) \\ &= 2\cos(x)+x^2\cos(x) \end{align}
The eighth derivative is
\begin{align} \frac{d^8}{dx^8}x^2\sin(x) &= 2\sin(x)+2x\cos(x)+2x\cos(x)-2x\sin(x)-x^2\cos(x) \\ &= 2\sin(x)-x^2\cos(x) \end{align}
The ninth derivative is
\begin{align} \frac{d^9}{dx^9}x^2\sin(x) &= 2\cos(x)-2x\sin(x)-2x\sin(x)+2x\sin(x)+x^2\cos(x) \\ &= 2\cos(x)+x^2\cos(x) \end{align}
The tenth derivative is
\begin{align} \frac{d^{10}}{dx^{10}}x^2\sin(x) &= 2\sin(x)+2x\cos(x)+2x\cos(x)-2x\sin(x)-x^2\cos(x) \\ &= 2\sin(x)-x^2\cos(x) \end{align}
The eleventh derivative is
\begin{align} \frac{d^{11}}{dx^{11}}x^2\sin(x) &= 2\cos(x)-2x\sin(x)-2x\sin(x)+2x\sin(x)+x^2\cos(x) \\ &= 2\cos(x)+x^2\cos(x) \end{align}
The twelfth derivative is
\begin{align} \frac{d^{12}}{dx^{12}}x^2\sin(x) &= 2\sin(x)+2x\cos(x)+2x\cos(x)-2x\sin(x)-x^2\cos(x) \\ &= 2\sin(x)-x^2\cos(x) \end{align}
